package com.grit.liferecorder
import android.app.Application; import com.grit.liferecorder.data.local.GritDatabase; import com.grit.liferecorder.data.repository.*; import com.grit.liferecorder.worker.WorkScheduler; import kotlinx.coroutines.*
class GritApp:Application(){ lateinit var container:AppContainer; override fun onCreate(){ super.onCreate(); container=AppContainer(this); WorkScheduler.scheduleMissedRoutineCheck(this); CoroutineScope(SupervisorJob()+Dispatchers.IO).launch{ container.categoryRepository.seedDefaults(); container.routineRepository.markMissedThrough() } } }
class AppContainer(app:Application){ val db=GritDatabase.get(app); val categoryRepository=CategoryRepository(db.categoryDao()); val projectRepository=ProjectRepository(db.projectDao()); val taskRepository=TaskRepository(db.taskDao()); val habitRepository=HabitRepository(db.trackedActionDao(),db.actionLogDao()); val routineRepository=RoutineRepository(db.routineDao(),db.routineStepDao(),db.routineOccurrenceDao()); val journalRepository=JournalRepository(db.journalDao()); val calendarRepository=CalendarRepository(db.taskDao(),db.actionLogDao(),db.routineOccurrenceDao(),db.journalDao()); val statsRepository=StatsRepository(db.taskDao(),db.actionLogDao(),db.routineOccurrenceDao(),db.journalDao()) }
